import React, { useCallback, useEffect, useMemo, useState } from 'react'
import { showToast } from '../../utils/toast'
import { useAuth } from '../../context/AuthContext'
import '../../styles/technician/technician-tasks.css'
import { taskService, pondService, productService, userService } from '../../services/api'

const STATUS_OPTIONS = [
  { value: 'ALL', label: 'Tất cả trạng thái' },
  { value: 'PENDING', label: 'Chờ xử lý' },
  { value: 'IN_PROGRESS', label: 'Đang thực hiện' },
  { value: 'COMPLETED', label: 'Hoàn thành' },
]

const normalize = (v) => String(v || '').toUpperCase()

const TechnicianTasks = () => {
  const { user } = useAuth()

  // ===== DATA =====
  const [tasks, setTasks] = useState([])
  const [ponds, setPonds] = useState([])
  const [products, setProducts] = useState([])
  const [workers, setWorkers] = useState([])

  // ===== UI STATE =====
  const [loading, setLoading] = useState(true)
  const [search, setSearch] = useState('')
  const [statusFilter, setStatusFilter] = useState('ALL')

  const [currentPage, setCurrentPage] = useState(1)
  const pageSize = 10

  const [selectedTask, setSelectedTask] = useState(null)
  const [isCreateOpen, setIsCreateOpen] = useState(false)

  // ===== FORM =====
  const initialForm = {
    task_type: '',
    pond_id: '',
    description: '',
    due_date: '',
    assigned_workers: [],
    product_id: '',
    quantity: 0,
  }

  const [form, setForm] = useState(initialForm)

  // =========================
  // FETCH DATA
  // =========================

  const fetchTasks = useCallback(async () => {
    try {
      const res = await taskService.getAllTasks()
      setTasks(res?.data?.data || [])
    } catch {
      showToast({ title: 'Không tải được công việc', type: 'error' })
    }
  }, [])

  const fetchPonds = useCallback(async () => {
    try {
      const res = await pondService.getAllPonds()
      setPonds(res?.data?.data || [])
    } catch {
      showToast({ title: 'Không tải được ao', type: 'error' })
    }
  }, [])

  const fetchProducts = useCallback(async () => {
    try {
      const res = await productService.getAllProducts()
      setProducts(res?.data?.data || [])
    } catch {
      showToast({ title: 'Không tải được sản phẩm', type: 'error' })
    }
  }, [])

  const fetchWorkers = useCallback(async () => {
    try {
      const res = await userService.getWorkers()
      setWorkers(res?.data?.data || [])
    } catch {
      showToast({ title: 'Không tải được worker', type: 'error' })
    }
  }, [])

  useEffect(() => {
    const load = async () => {
      setLoading(true)
      await Promise.all([
        fetchTasks(),
        fetchPonds(),
        fetchProducts(),
        fetchWorkers(),
      ])
      setLoading(false)
    }

    load()
  }, [fetchTasks, fetchPonds, fetchProducts, fetchWorkers])

  // =========================
  // FILTER LOGIC
  // =========================

  const filteredTasks = useMemo(() => {
    const s = search.trim().toLowerCase()

    return tasks.filter(t => {
      const matchSearch =
        !s ||
        t.task_title?.toLowerCase().includes(s) ||
        t.pond_name?.toLowerCase().includes(s)

      const matchStatus =
        statusFilter === 'ALL' ||
        normalize(t.status) === statusFilter

      return matchSearch && matchStatus
    })
  }, [tasks, search, statusFilter])

  const totalPages = Math.max(1, Math.ceil(filteredTasks.length / pageSize))

  const paginatedTasks = useMemo(() => {
    const start = (currentPage - 1) * pageSize
    return filteredTasks.slice(start, start + pageSize)
  }, [filteredTasks, currentPage])

  // =========================
  // FILTER HELPERS
  // =========================

  const filteredPonds = useMemo(() => {
    if (!form.task_type) return ponds

    switch (form.task_type) {
      case 'FEEDING':
      case 'TREATMENT':
      case 'HARVEST':
        return ponds.filter(p => p.status === 'DANG_NUOI')

      case 'POND_PROCESS':
        return ponds.filter(p => p.status === 'DANG_CAI_TAO')

      default:
        return ponds
    }
  }, [ponds, form.task_type])

  const filteredProducts = useMemo(() => {
    if (!form.task_type) return []

    switch (form.task_type) {
      case 'FEEDING':
        return products.filter(p => p.type === 'FEED')
      case 'TREATMENT':
        return products.filter(p => p.type === 'MEDICINE')
      case 'POND_PROCESS':
        return products.filter(p => p.type === 'CHEMICAL')
      default:
        return []
    }
  }, [products, form.task_type])

  // =========================
  // HANDLERS
  // =========================

  const toggleWorker = (id) => {
    setForm(prev => {
      const list = prev.assigned_workers || []
      const exists = list.includes(id)

      return {
        ...prev,
        assigned_workers: exists
          ? list.filter(x => x !== id)
          : [...list, id],
      }
    })
  }

  const handleCreateTask = async () => {
    try {
      await taskService.createTask(form)

      showToast({ title: 'Tạo công việc thành công', type: 'success' })

      setForm(initialForm)
      setIsCreateOpen(false)
      fetchTasks()
    } catch {
      showToast({ title: 'Tạo công việc thất bại', type: 'error' })
    }
  }

  const handleStatusChange = async (taskId, status) => {
    try {
      await taskService.updateTaskStatus(taskId, status)
      showToast({ title: 'Cập nhật thành công', type: 'success' })
      fetchTasks()
    } catch {
      showToast({ title: 'Lỗi cập nhật trạng thái', type: 'error' })
    }
  }

  // =========================
  // UI HELPERS
  // =========================

  const getStatusLabel = (status) => {
    switch (normalize(status)) {
      case 'PENDING': return 'Chờ xử lý'
      case 'IN_PROGRESS': return 'Đang thực hiện'
      case 'COMPLETED': return 'Hoàn thành'
      default: return status
    }
  }

  const getStatusClass = (status) => {
    switch (normalize(status)) {
      case 'PENDING': return 'task-status--pending'
      case 'IN_PROGRESS': return 'task-status--progress'
      case 'COMPLETED': return 'task-status--done'
      default: return ''
    }
  }

  const formatDate = (v) =>
    v ? new Date(v).toLocaleString('vi-VN') : '-'

  // =========================
  // LOADING
  // =========================

  if (loading) {
    return (
      <div className="dashboard admin-page">
        <div className="flex-center table-loading-container">
          <div className="spinner" />
        </div>
      </div>
    )
  }

  // =========================
  // RENDER
  // =========================

  return (
    <div className="dashboard admin-page technician-tasks">

      <div className="table-container table-panel">

        {/* HEADER */}
        <div className="table-header">
          <div>
            <h2>Quản lý công việc</h2>
            <p className="table-subtitle">Phân công & theo dõi công việc</p>
          </div>

          <button className="btn btn-primary" onClick={() => setIsCreateOpen(true)}>
            + Phân công công việc
          </button>
        </div>

        {/* FILTER */}
        <div className="table-toolbar">
          <input
            placeholder="Tìm công việc / ao..."
            value={search}
            onChange={(e) => {
              setSearch(e.target.value)
              setCurrentPage(1)
            }}
          />

          <select
            value={statusFilter}
            onChange={(e) => {
              setStatusFilter(e.target.value)
              setCurrentPage(1)
            }}
          >
            {STATUS_OPTIONS.map(o => (
              <option key={o.value} value={o.value}>{o.label}</option>
            ))}
          </select>
        </div>

        {/* TABLE */}
        <table className="table-base">
          <thead>
            <tr>
              <th>Công việc</th>
              <th>Ao</th>
              <th>Người giao</th>
              <th>Người nhận</th>
              <th>Hạn</th>
              <th>Trạng thái</th>
              <th></th>
            </tr>
          </thead>

          <tbody>
            {paginatedTasks.length === 0 ? (
              <tr>
                <td colSpan="7">Không có dữ liệu</td>
              </tr>
            ) : (
              paginatedTasks.map(t => (
                <tr key={t.task_id}>
                  <td>
                    <b>{t.task_title}</b>
                    <div>{t.description}</div>
                  </td>

                  <td>{t.pond_name || '-'}</td>
                  <td>{t.assigned_by_name || '-'}</td>
                  <td>{t.assigned_to_name || '-'}</td>
                  <td>{formatDate(t.due_date)}</td>

                  <td>
                    <span className={getStatusClass(t.status)}>
                      {getStatusLabel(t.status)}
                    </span>
                  </td>

                  <td>
                    <button onClick={() => setSelectedTask(t)}>ⓘ</button>
                  </td>
                </tr>
              ))
            )}
          </tbody>
        </table>

        {/* PAGINATION */}
        <div className="table-pagination">
          <span>{filteredTasks.length} công việc</span>

          <div>
            <button
              disabled={currentPage === 1}
              onClick={() => setCurrentPage(p => p - 1)}
            >
              ‹
            </button>

            <span>{currentPage}</span>

            <button
              disabled={currentPage >= totalPages}
              onClick={() => setCurrentPage(p => p + 1)}
            >
              ›
            </button>
          </div>
        </div>
      </div>

      {/* DETAIL MODAL */}
      {selectedTask && (
        <div className="modal" onClick={() => setSelectedTask(null)}>
          <div className="modal-content" onClick={e => e.stopPropagation()}>

            <h3>Chi tiết công việc</h3>

            <p><b>{selectedTask.task_title}</b></p>
            <p>{selectedTask.description}</p>

            <select
              value={selectedTask.status}
              onChange={(e) =>
                handleStatusChange(selectedTask.task_id, e.target.value)
              }
            >
              <option value="PENDING">Chờ xử lý</option>
              <option value="IN_PROGRESS">Đang thực hiện</option>
              <option value="COMPLETED">Hoàn thành</option>
            </select>

            <button onClick={() => setSelectedTask(null)}>
              Đóng
            </button>
          </div>
        </div>
      )}

      {/* CREATE MODAL (basic skeleton - ready to extend) */}
      {isCreateOpen && (
        <div className="modal" onClick={() => setIsCreateOpen(false)}>
          <div className="modal-content" onClick={e => e.stopPropagation()}>

            <h3>Tạo công việc</h3>

            <select
              value={form.task_type}
              onChange={(e) =>
                setForm({ ...form, task_type: e.target.value, pond_id: '' })
              }
            >
              <option value="">Loại công việc</option>
              <option value="FEEDING">Cho ăn</option>
              <option value="TREATMENT">Cho thuốc</option>
              <option value="HARVEST">Thu hoạch</option>
              <option value="POND_PROCESS">Xử lý ao</option>
            </select>

            <select
              value={form.pond_id}
              onChange={(e) => setForm({ ...form, pond_id: e.target.value })}
            >
              <option value="">Chọn ao</option>
              {filteredPonds.map(p => (
                <option key={p.pond_id} value={p.pond_id}>
                  {p.pond_name}
                </option>
              ))}
            </select>

            <textarea
              placeholder="Mô tả"
              value={form.description}
              onChange={(e) =>
                setForm({ ...form, description: e.target.value })
              }
            />

            <input
              type="datetime-local"
              value={form.due_date}
              onChange={(e) =>
                setForm({ ...form, due_date: e.target.value })
              }
            />

            <div className="modal-actions">
              <button onClick={() => setIsCreateOpen(false)}>Hủy</button>
              <button onClick={handleCreateTask}>Tạo</button>
            </div>

          </div>
        </div>
      )}

    </div>
  )
}

export default TechnicianTasks
